select count(*) from postgres.comments as c, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.posts as p where pl.postid = p.id and c.postid = p.id and v.postid = p.id and ph.postid = p.id and pl.linktypeid=1 and pl.creationdate>=timestamp '2010-10-19 15:02:42' and ph.creationdate<=timestamp '2014-06-18 17:14:07' and v.creationdate>=timestamp '2010-07-20 00:00:00';
